// Helpers
// ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ

fn progress_bar(done: usize, total: usize, width: usize) -> String {
    if total == 0 {
        return "‚ñë".repeat(width);
    }
    let filled = (done * width) / total;
    let empty = width - filled;
    format!("‚ñà{}‚ñë{}", "‚ñà".repeat(filled.saturating_sub(1)), "‚ñë".repeat(empty))
}

/// ISO 639-1 (2-letter) to ISO 639-2/T (3-letter) for ffmpeg metadata
pub fn lang_to_iso639_2(code: &str) -> &str {
    match code {
        "en" => "eng",
        "ru" => "rus",
        "zh_cn" | "zh_tw" | "zh" => "zho",
        "ja" => "jpn",
        "ko" => "kor",
        "fr" => "fra",
        "de" => "deu",
        "es" => "spa",
        "pt" => "por",
        "it" => "ita",
        "nl" => "nld",
        "pl" => "pol",
        "tr" => "tur",
        "ar" => "ara",
        "th" => "tha",
        "vi" => "vie",
        "id" => "ind",
        "hi" => "hin",
        "uk" => "ukr",
        "sv" => "swe",
        "da" => "dan",
        "fi" => "fin",
        "no" => "nor",
        "el" => "ell",
        "cs" => "ces",
        "ro" => "ron",
        "hu" => "hun",
        "he" => "heb",
        "fa" => "fas",
        "bn" => "ben",
        "ta" => "tam",
        "ka" => "kat",
        _ => code,
    }
}

/// Get display name for a language code
pub fn lang_display_name(code: &str) -> &str {
    match code {
        "en" => "English",
        "ru" => "Russian",
        "zh_cn" => "Chinese (Simplified)",
        "zh_tw" => "Chinese (Traditional)",
        "ja" => "Japanese",
        "ko" => "Korean",
        "fr" => "French",
        "de" => "German",
        "es" => "Spanish",
        "pt" => "Portuguese",
        "it" => "Italian",
        "uk" => "Ukrainian",
        "ar" => "Arabic",
        "hi" => "Hindi",
        "th" => "Thai",
        "vi" => "Vietnamese",
        "tr" => "Turkish",
        _ => code,
    }
}

/// Determine auto target language based on detected source language.
/// English ‚Üî Russian by default. Other languages ‚Üí English.
pub fn auto_target_language(detected: &str) -> &str {
    match detected {
        "en" | "english" => "ru",
        "ru" | "russian" => "en",
        _ => "en",
    }
}
